import React, { useEffect, useState } from "react";
import axios from "axios";
import { startTracking, getData } from "./tracker";

function ColorGame({ onNext }) {
  const [matched, setMatched] = useState(new Set());

  useEffect(() => {
    startTracking();
  }, []);

  const colors = ['red', 'blue', 'green', 'yellow', 'orange', 'purple', 'pink', 'brown', 'cyan', 'magenta'];
  const boxColors = ['red', 'blue', 'green', 'yellow', 'orange', 'purple', 'pink', 'brown'];
  const shuffledBoxes = [...boxColors].sort(() => Math.random() - 0.5);

  const colorEmojis = {
    red: '🔴',
    blue: '🔵',
    green: '🟢',
    yellow: '🟡',
    orange: '🟠',
    purple: '💜',
    pink: '🩷',
    brown: '🤎',
    cyan: '🟦',
    magenta: '🟣'
  };

  const boxBackgrounds = {
    red: "#fb0303",
    blue: "#ADD8E6",
    green: "#02f702",
    yellow: "#FFFFE0",
    orange: "#cf5701",
    purple: "#bd05fb",
    pink: "#f853dad1",
    brown: "#D2B48C"
  };

  const handleDrop = async (draggedColor, boxColor) => {
    if (draggedColor === boxColor) {
      if (!matched.has(boxColor)) {
        setMatched(prev => new Set(prev).add(boxColor));
        alert("Correct ✅");
      } else {
        alert("Already matched! ✅");
      }
    } else {
      alert("Wrong ❌");
    }

    const data = getData();

    try {
      await axios.post("http://localhost:5000/save", {
        activity: "color_game",
        ...data,
      });
    } catch (err) {
      console.error("ColorGame save failed:", err);
      alert("Progress could not be saved to the server.");
    }
  };

  return (
    <div style={{ textAlign: "center", paddingTop: "50px", background: "#FFFACD", minHeight: "100vh" }}>
      <h1>Match Colors 🌈</h1>

      {/* Draggable Colors */}
      <div style={{ display: "flex", flexWrap: "wrap", justifyContent: "center", marginBottom: "40px" }}>
        {colors.map(color => (
          <div
            key={color}
            draggable
            onDragStart={(e) => e.dataTransfer.setData("color", color)}
            style={{
              fontSize: "40px",
              margin: "10px",
              cursor: "grab",
            }}
          >
            {colorEmojis[color]}
          </div>
        ))}
      </div>

      {/* Drop Boxes */}
      <div style={{ display: "flex", flexWrap: "wrap", justifyContent: "center" }}>
        {shuffledBoxes.map(boxColor => (
          <div
            key={boxColor}
            onDragOver={(e) => e.preventDefault()}
            onDrop={(e) => {
              const draggedColor = e.dataTransfer.getData("color");
              handleDrop(draggedColor, boxColor);
            }}
            style={{
              width: "150px",
              height: "150px",
              backgroundColor: matched.has(boxColor) ? boxBackgrounds[boxColor] : "gray",
              margin: "10px",
              lineHeight: "150px",
              border: matched.has(boxColor) ? "5px solid green" : "2px solid #ccc",
              position: "relative",
              borderRadius: "10px",
            }}
          >
            {boxColor.charAt(0).toUpperCase() + boxColor.slice(1)} Box
            {matched.has(boxColor) && <span style={{ position: "absolute", top: "5px", right: "5px", fontSize: "30px" }}>✅</span>}
          </div>
        ))}
      </div>

      {matched.size === 8 && (
        <button
          onClick={() => onNext && onNext()}
          style={{
            fontSize: "20px",
            padding: "15px 30px",
            backgroundColor: "#4CAF50",
            color: "white",
            border: "none",
            borderRadius: "10px",
            cursor: "pointer",
            marginTop: "20px",
            fontWeight: "bold",
          }}
        >
          Next ➡️
        </button>
      )}
    </div>
  );
}

export default ColorGame;
